import React, { useState, useEffect } from 'react';
import { Bell, ChevronRight } from 'lucide-react';
import { AnnouncementCard } from './AnnouncementCard';

/**
 * RecentAnnouncementsWidget Component
 * Displays recent announcements on the main dashboard
 */
export function RecentAnnouncementsWidget() {
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading] = useState(true);

  // Load announcements from localStorage
  useEffect(() => {
    const loadAnnouncements = () => {
      const saved = localStorage.getItem('announcements');
      if (saved) {
        try {
          const data = JSON.parse(saved);
          // Filter published announcements and sort
          const published = data
            .filter(ann => ann.isPublished)
            .sort((a, b) => {
              // Pinned first
              if (a.isPinned !== b.isPinned) {
                return b.isPinned ? 1 : -1;
              }
              // Then by date
              return new Date(b.publishDate) - new Date(a.publishDate);
            })
            .slice(0, 5); // Show latest 5
          setAnnouncements(published);
        } catch (err) {
          console.error('Error loading announcements:', err);
        }
      }
      setLoading(false);
    };

    loadAnnouncements();

    // Listen for updates from other tabs/components
    const handleStorageChange = (e) => {
      if (e.key === 'announcements' || e.detail) {
        loadAnnouncements();
      }
    };

    window.addEventListener('storage', handleStorageChange);
    window.addEventListener('announcementsUpdated', handleStorageChange);

    return () => {
      window.removeEventListener('storage', handleStorageChange);
      window.removeEventListener('announcementsUpdated', handleStorageChange);
    };
  }, []);

  if (loading) {
    return (
      <div className="recent-announcements-widget">
        <div className="loading-state">Loading announcements...</div>
      </div>
    );
  }

  return (
    <div className="recent-announcements-widget">
      {/* Widget Header */}
      <div className="widget-header">
        <div className="header-left">
          <Bell size={20} />
          <h3>Recent Announcements</h3>
        </div>
        {announcements.length > 0 && (
          <Link to="/dashboard" className="view-all-link">
            View All
            <ArrowRight size={16} />
          </Link>
        )}
      </div>

      {/* Content */}
      {announcements.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">📢</div>
          <p>No announcements yet</p>
        </div>
      ) : (
        <div className="announcements-list">
          {announcements.map(ann => (
            <AnnouncementCard
              key={ann.id}
              announcement={ann}
              isAdmin={false}
              compact={true}
              onEdit={() => {}}
              onDelete={() => {}}
              onPin={() => {}}
              onTogglePublish={() => {}}
            />
          ))}
        </div>
      )}
    </div>
  );
}
